content.text:
The syntax of a `while` loop is:
```javascript
while (condition) {
  // code to execute
}
```
- **Condition**: An expression checked before each iteration. If `true`, the code block runs; if `false`, the loop stops.
- The condition is evaluated before each iteration.

content.code:
// Basic while loop example
let i = 0;
while (i < 5) {
  console.log(i);
  i++;
}
// Output:
// 0
// 1
// 2
// 3
// 4

// while loop with an array
const fruits = ['apple', 'pear', 'orange'];
let i = 0;
while (i < fruits.length) {
  console.log(fruits[i]);
  i++;
}
// Output:
// apple
// pear
// orange

// break and continue example
let i = 0;
while (i < 5) {
  if (i === 3) {
    break; // stops the loop
  }
  console.log(i);
  i++;
}
// Output:
// 0
// 1
// 2

i = 0;
while (i < 5) {
  i++;
  if (i === 3) {
    continue; // skips 3
  }
  console.log(i);
}
// Output:
// 1
// 2
// 4
// 5

// Dynamic while loop example
let sum = 0;
let number = 1;
while (sum < 10) {
  sum += number;
  console.log(`Sum: ${sum}, Number: ${number}`);
  number++;
}
// Output:
// Sum: 1, Number: 1
// Sum: 3, Number: 2
// Sum: 6, Number: 3
// Sum: 10, Number: 4

// Error-prone example
// Error: Infinite loop
// let i = 0;
// while (i < 5) {
//   console.log(i);
//   // i++ is missing, causing an infinite loop
// }
// Correct approach
let i = 0;
while (i < 5) {
  console.log(i);
  i++;
}
// Output:
// 0
// 1
// 2
// 3
// 4

